package com.school.sis.grade.entity;
import com.school.sis.common.audit.AuditableEntity; import com.school.sis.setup.entity.ActiveStatus; import jakarta.persistence.*; import java.util.*;
@Entity @Table(name="grading_scales") public class GradingScale extends AuditableEntity {
 @Id private UUID id; @Column(name="scale_code",nullable=false,unique=true) private String scaleCode; @Column(name="scale_name",nullable=false) private String scaleName; @Column(nullable=false) private int version=1; @Enumerated(EnumType.STRING) @Column(nullable=false) private ActiveStatus status=ActiveStatus.ACTIVE; @OneToMany(mappedBy="scale",cascade=CascadeType.ALL,orphanRemoval=true) private List<GradingScaleBand> bands=new ArrayList<>();
 @PrePersist void pre(){if(id==null)id=UUID.randomUUID();} public UUID getId(){return id;} public String getScaleCode(){return scaleCode;} public void setScaleCode(String v){scaleCode=v;} public String getScaleName(){return scaleName;} public void setScaleName(String v){scaleName=v;} public int getVersion(){return version;} public void setVersion(int v){version=v;} public ActiveStatus getStatus(){return status;} public void setStatus(ActiveStatus v){status=v;} public List<GradingScaleBand> getBands(){return bands;} public void setBands(List<GradingScaleBand> v){bands.clear();if(v!=null)v.forEach(this::addBand);} public void addBand(GradingScaleBand b){b.setScale(this);bands.add(b);}
}
